import{_ as e,o,c as t,ag as r}from"./chunks/framework.DUza98OV.js";const m=JSON.parse('{"title":"HashMap 原理","description":"","frontmatter":{},"headers":[],"relativePath":"java/hashmap.md","filePath":"java/hashmap.md","lastUpdated":1776563785000}'),h={name:"java/hashmap.md"};function l(s,a,i,d,n,c){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="hashmap-原理" tabindex="-1">HashMap 原理 <a class="header-anchor" href="#hashmap-原理" aria-label="Permalink to &quot;HashMap 原理&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>面试里经常会问：<code>HashMap</code> 为什么查询快？扩容时为什么会影响性能？在高并发场景下直接使用会有什么风险？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p><code>HashMap</code> 的核心结构是数组 + 链表 + 红黑树。键经过哈希计算后映射到数组桶位，桶位冲突时先挂链表，链表长度超过阈值并且容量足够时再树化为红黑树，从而避免极端碰撞导致的线性查找。</p><p>扩容发生在元素个数超过 <code>capacity * loadFactor</code> 时，默认负载因子是 <code>0.75</code>。扩容会创建更大的数组，并把原有元素重新分配到新桶位，所以这是一个成本较高的操作。如果容量预估不足，业务高峰期就容易出现频繁扩容。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>查询效率通常接近 <code>O(1)</code>，但严重哈希冲突时会退化。</li><li>JDK 8 之后用红黑树优化长链表，降低最坏情况复杂度。</li><li>扩容本质是一次 rehash，既消耗 CPU，也会带来瞬时延迟抖动。</li><li><code>HashMap</code> 线程不安全，多线程场景应考虑 <code>ConcurrentHashMap</code>。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>理解 <code>HashMap</code> 不能只停留在“数组加链表”这一层，更重要的是要掌握哈希分布、扩容成本和并发语义，这些点决定了它在真实系统中的适用边界。</p>',10)])])}const u=e(h,[["render",l]]);export{m as __pageData,u as default};
